const healthcareBySlug: Record<string, HealthcareProfile> = {};
for (const profile of healthcareProfiles) {
  healthcareBySlug[profile.citySlug] = profile;
}
const retirementBySlug: Record<string, RetirementProfile> = {};
for (const profile of retirementProfiles) {
  retirementBySlug[profile.citySlug] = profile;
}
const facilitiesByCity: Record<string, MedicalFacility[]> = {};
for (const facility of medicalFacilities) {
  (facilitiesByCity[facility.citySlug] ??= []).push(facility);
}

const VALID_HEALTHCARE_CATEGORIES: ReadonlySet<string> = new Set([
  "global_medical_hub", "major_healthcare_center", "regional_healthcare_center",
  "healthcare_access_city", "developing_healthcare_market", "mixed",
]);
const VALID_RETIREMENT_CATEGORIES: ReadonlySet<string> = new Set([
  "premium_retirement", "active_retirement", "affordable_retirement",
  "urban_retirement", "nature_retirement", "mixed",
]);
const VALID_FACILITY_TYPES: ReadonlySet<string> = new Set([
  "general_hospital", "specialist_hospital", "university_hospital",
  "medical_center", "community_hospital",
]);
const VALID_SERVICE_LEVELS: ReadonlySet<string> = new Set(["local", "regional", "national"]);

/** Build-time integrity guard — throws (failing `next build`) on any invalid record. */
function assertHealthcareIntegrity(
  healthcare: readonly HealthcareProfile[],
  retirement: readonly RetirementProfile[],
  facilities: readonly MedicalFacility[],
): void {
  const errors: string[] = [];
  const inRange = (n: number) => typeof n === "number" && Number.isFinite(n) && n >= 0 && n <= 100;
  const hcSeen = new Set<string>();
  for (const h of healthcare) {
    if (hcSeen.has(h.citySlug)) errors.push(`duplicate healthcare citySlug: ${h.citySlug}`);
    hcSeen.add(h.citySlug);
    const scores = [
      h.healthcareScore, h.healthcareAccessScore, h.hospitalAvailabilityScore,
      h.specialistCareScore, h.preventativeCareScore, h.emergencyCareScore,
      h.healthcareAffordabilityScore,
    ];
    if (scores.some((n) => !inRange(n))) errors.push(`${h.citySlug}: healthcare score out of range`);
    if (!VALID_HEALTHCARE_CATEGORIES.has(h.healthcareCategory))
      errors.push(`${h.citySlug}: invalid healthcareCategory`);
    if ([h.healthcareSummary, h.medicalAccessSummary, h.healthcareEnvironmentSummary]
      .some((t) => typeof t !== "string" || t.length === 0))
      errors.push(`${h.citySlug}: missing healthcare summary`);
  }
  const retSeen = new Set<string>();
  for (const r of retirement) {
    if (retSeen.has(r.citySlug)) errors.push(`duplicate retirement citySlug: ${r.citySlug}`);
    retSeen.add(r.citySlug);
    const scores = [
      r.retirementScore, r.affordabilityScore, r.healthcareSupportScore,
      r.climateComfortScore, r.safetySupportScore, r.walkabilityScore,
      r.accessibilityScore, r.activeLifestyleScore,
    ];
    if (scores.some((n) => !inRange(n))) errors.push(`${r.citySlug}: retirement score out of range`);
    if (!VALID_RETIREMENT_CATEGORIES.has(r.retirementCategory))
      errors.push(`${r.citySlug}: invalid retirementCategory`);
    if ([r.retirementSummary, r.lifestyleSummary, r.affordabilitySummary, r.activeLivingSummary]
      .some((t) => typeof t !== "string" || t.length === 0))
      errors.push(`${r.citySlug}: missing retirement summary`);
  }
  for (const slug of hcSeen) if (!retSeen.has(slug)) errors.push(`${slug}: healthcare without retirement`);
  for (const slug of retSeen) if (!hcSeen.has(slug)) errors.push(`${slug}: retirement without healthcare`);
  const idSeen = new Set<string>();
  const facCount = new Map<string, number>();
  for (const f of facilities) {
    if (idSeen.has(f.id)) errors.push(`duplicate facility id: ${f.id}`);
    idSeen.add(f.id);
    if (!hcSeen.has(f.citySlug)) errors.push(`${f.id}: facility references unknown city ${f.citySlug}`);
    if (!VALID_FACILITY_TYPES.has(f.type)) errors.push(`${f.id}: invalid type ${f.type}`);
    if (!VALID_SERVICE_LEVELS.has(f.serviceLevel)) errors.push(`${f.id}: invalid serviceLevel`);
    if (!f.name) errors.push(`${f.id}: missing name`);
    facCount.set(f.citySlug, (facCount.get(f.citySlug) ?? 0) + 1);
  }
  for (const slug of hcSeen) {
    const n = facCount.get(slug) ?? 0;
    if (n < 3 || n > 10) errors.push(`${slug}: ${n} medical facilities (must be 3-10)`);
  }
  if (errors.length > 0) {
    throw new Error(`healthcare integrity failure:\n${errors.join("\n")}`);
  }
}

assertHealthcareIntegrity(healthcareProfiles, retirementProfiles, medicalFacilities);

export function getHealthcare(citySlug: string): HealthcareProfile | undefined {
  return healthcareBySlug[citySlug];
}

export function hasHealthcare(citySlug: string): boolean {
  return Object.prototype.hasOwnProperty.call(healthcareBySlug, citySlug);
}

export function getAllHealthcareProfiles(): readonly HealthcareProfile[] {
  return healthcareProfiles;
}

export function getRetirement(citySlug: string): RetirementProfile | undefined {
  return retirementBySlug[citySlug];
}

export function hasRetirement(citySlug: string): boolean {
  return Object.prototype.hasOwnProperty.call(retirementBySlug, citySlug);
}

export function getAllRetirementProfiles(): readonly RetirementProfile[] {
  return retirementProfiles;
}

export function getMedicalFacilitiesForCity(citySlug: string): readonly MedicalFacility[] {
  return facilitiesByCity[citySlug] ?? [];
}

export function getAllMedicalFacilities(): readonly MedicalFacility[] {
  return medicalFacilities;
}
